@assets @vite('resources/js/passkeys.js') @endassets
<div x-data="{supported:false,show:false,name:'',loading:false,error:null,init(){this.supported=Boolean(window.Passkeys?.isSupported());window.addEventListener('passkeys:ready',()=>this.supported=Boolean(window.Passkeys?.isSupported()),{once:true})},async register(){if(!this.name.trim())return;this.loading=true;this.error=null;try{await window.Passkeys.register({name:this.name});this.name='';this.show=false;await $wire.loadPasskeys()}catch(e){if(e.constructor?.name!=='UserCancelledError')this.error=e.message}finally{this.loading=false}}}">
<p x-show="!supported" class="text-sm text-slate-500">Passkeys are not supported in this browser.</p>
<div x-show="supported && !show"><x-ui.button x-on:click="show=true">Add passkey</x-ui.button></div>
<div x-show="supported && show" x-cloak class="grid gap-4 rounded-2xl border border-slate-200 bg-slate-50 p-4 dark:border-slate-700 dark:bg-slate-800"><label class="grid gap-2 text-sm font-semibold">Passkey name<input x-model="name" class="rounded-xl border border-slate-300 bg-white px-4 py-3 dark:border-slate-600 dark:bg-slate-900" placeholder="e.g., Phone or laptop"></label><p class="text-sm text-slate-500">Give this passkey a name to identify it later.</p><p x-show="error" x-text="error" class="text-sm text-red-600"></p><div class="flex gap-2"><x-ui.button x-on:click="register()" x-bind:disabled="loading || !name.trim()"><span x-text="loading ? 'Registering...' : 'Register passkey'"></span></x-ui.button><x-ui.button variant="secondary" x-on:click="show=false">Cancel</x-ui.button></div></div>
</div>
